import React from 'react';
import { Link } from 'react-router-dom';
import './Payment.css';

const PaymentSuccess = () => {
  return (
    <div className="paymentpage">
      <div className="donate success-container">
        <div className="success-content">
          <h2>Thank You for Your Donation!</h2>
          <p>Your contribution will help us protect wildlife and their habitats.</p>
          <div className="success-details">
            <p>A confirmation email has been sent to your registered email address.</p>
            <p>Your support makes a real difference in our conservation efforts.</p>
          </div>
          <div className="success-actions">
            <Link to="/" className="home-button">Return to Home</Link>
            <Link to="/events" className="events-button">View Upcoming Events</Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PaymentSuccess;
